const leadRows = $items('Read Leads (Send)', 0, 0).map(i => i.json || {});
const stateRows = items.map(i => i.json || {}).filter(r => String(r.lead_id || '').trim());
const stateMap = new Map(stateRows.map(r => [String(r.lead_id).trim(), r]));

const now = new Date();
const today = now.toISOString().slice(0, 10);
const dailyCap = Number($env.DAILY_SEND_CAP || 10);
const sentToday = leadRows.filter(r => String(r.last_contacted_at || '').slice(0, 10) === today).length;
if (sentToday >= dailyCap) return [];

const approvedLeads = leadRows
  .filter(r => String(r.status || '').toUpperCase() === 'APPROVED')
  .sort((a, b) => String(a.lead_id || '').localeCompare(String(b.lead_id || '')));
if (!approvedLeads.length) return [];

function hashText(s) {
  let h = 0;
  for (let i = 0; i < s.length; i++) {
    h = ((h << 5) - h) + s.charCodeAt(i);
    h |= 0;
  }
  return String(Math.abs(h));
}

for (const lead of approvedLeads) {
  const leadId = String(lead.lead_id || '').trim();
  if (!leadId) continue;
  const username = String(lead.telegram_username || '').replace(/^@/, '').trim();
  if (!username) continue;
  const state = stateMap.get(leadId) || {};
  const draft = String(state.draft_message || '').trim();
  if (!draft) continue;

  const followupCount = Number(lead.followup_count || 0);
  const idem = `${leadId}-${followupCount}-${hashText(draft)}`;
  if (String(state.last_idempotency_key || '') === idem && String(lead.last_contacted_at || '').slice(0, 10) === today) {
    continue;
  }

  const minDelay = Number($env.SEND_DELAY_MIN_SECONDS || 180);
  const maxDelay = Number($env.SEND_DELAY_MAX_SECONDS || 600);
  const delay = Math.floor(Math.random() * (maxDelay - minDelay + 1)) + minDelay;
  const isFollowup = !!String(lead.next_followup_at || '').trim();

  return [{
    json: {
      lead_id: leadId,
      name: String(lead.name || ''),
      telegram_username: username,
      company: String(lead.company || ''),
      role: String(lead.role || ''),
      source_url: String(lead.source_url || ''),
      status: String(lead.status || 'APPROVED'),
      last_contacted_at: String(lead.last_contacted_at || ''),
      next_followup_at: String(lead.next_followup_at || ''),
      followup_count: followupCount,
      telegram_chat_id: String(state.telegram_chat_id || ''),
      draft_message: draft,
      research_snippet: String(state.research_snippet || ''),
      memory_summary: String(state.memory_summary || ''),
      approval_feedback: String(state.approval_feedback || ''),
      last_reply_received: String(state.last_reply_received || ''),
      last_reply_at: String(state.last_reply_at || ''),
      last_idempotency_key: String(state.last_idempotency_key || ''),
      last_sent_type: String(state.last_sent_type || ''),
      last_error: String(state.last_error || ''),
      last_error_at: String(state.last_error_at || ''),
      message_history: String(state.message_history || ''),
      updated_at: String(state.updated_at || ''),
      is_followup: isFollowup,
      send_delay_sec: delay,
      idempotency_key: idem,
      outbound_text: draft,
    }
  }];
}

return [];

const sec = Number($json.send_delay_sec || 180);
await new Promise(resolve => setTimeout(resolve, sec * 1000));
return items;

const lead = $items('Select Approved Lead To Send', 0, 0)[0].json;
const resolveResp = items[0].json || {};
const resolvedChatId = resolveResp.telegram_user_id || lead.telegram_chat_id || '';
const resolvedUsername = String(resolveResp.username || lead.telegram_username || '').replace(/^@/, '');
return [{ json: {
  ...lead,
  telegram_chat_id: resolvedChatId,
  telegram_username: resolvedUsername,
} }];

const lead = $items('Build Send Payload', 0, 0)[0].json;
const now = new Date();
const nowIso = now.toISOString();
const minDays = Number($env.FOLLOWUP_MIN_DAYS || 2);
const maxDays = Number($env.FOLLOWUP_MAX_DAYS || 3);
const days = Math.floor(Math.random() * (maxDays - minDays + 1)) + minDays;
const next = new Date(now.getTime() + days * 24 * 60 * 60 * 1000).toISOString();
const wasFollowup = !!lead.is_followup;
const followups = Number(lead.followup_count || 0) + (wasFollowup ? 1 : 0);
const historyLine = `${nowIso}|OUTBOUND|${wasFollowup ? 'FOLLOWUP' : 'FIRST'}|${lead.outbound_text}`;
return [{ json: {
  ...lead,
  status: 'SENT',
  last_contacted_at: nowIso,
  next_followup_at: next,
  followup_count: followups,
  telegram_chat_id: String(lead.telegram_chat_id || ''),
  last_idempotency_key: lead.idempotency_key,
  last_sent_type: wasFollowup ? 'FOLLOWUP' : 'FIRST',
  last_error: '',
  last_error_at: '',
  message_history: [String(lead.message_history || ''), historyLine].filter(Boolean).join('\n'),
  updated_at: nowIso,
} }];

const lead = $items('Build Send Payload', 0, 0)[0].json;
const sendRes = items[0].json || {};
const code = sendRes.result?.error_code || 'SEND_FAILED';
const nowIso = new Date().toISOString();
return [{ json: {
  ...lead,
  status: 'FAILED',
  last_error: code,
  last_error_at: nowIso,
  message_history: [String(lead.message_history || ''), `${nowIso}|ERROR|${code}`].filter(Boolean).join('\n'),
  updated_at: nowIso,
  ops_failure_message: `Send failed for lead_id ${lead.lead_id}: ${code}`,
} }];

const item = $json || {};
const allowedChatId = String($env.OPS_CHAT_ID || '').trim();
let action = '';
let leadId = '';
let feedback = '';
let actor = '';
let chatId = '';
let callbackId = '';

function extractLeadIdFromCard(text) {
  const t = String(text || '');
  const m = t.match(/lead_id:\s*([^\n]+)/i);
  if (!m) return '';
  return String(m[1] || '').trim().split(/\s+/)[0].replace(/[^A-Za-z0-9_-]/g, '') || '';
}

if (item.callback_query) {
  const data = String(item.callback_query.data || '').trim();
  const parts = data.split(':');
  action = String(parts.shift() || '').toLowerCase();
  leadId = String(parts.join(':') || '').trim();
  if (!leadId) leadId = extractLeadIdFromCard(item.callback_query.message?.text || '');
  actor = String(item.callback_query.from?.username || item.callback_query.from?.id || 'unknown');
  chatId = String(item.callback_query.message?.chat?.id || '');
  callbackId = String(item.callback_query.id || '');
  if (action === 'edit') action = 'edit_request';
} else if (item.message) {
  const text = String(item.message.text || '').trim();
  actor = String(item.message.from?.username || item.message.from?.id || 'unknown');
  chatId = String(item.message.chat?.id || '');
  const low = text.toLowerCase();
  if (low === '/draftnow' || low === 'draftnow') {
    action = 'draftnow';
  } else {
    const m = text.match(/^\/?(approve|edit|skip|dnc)\s+([^\s]+)\s*(.*)$/i);
    if (m) {
      action = String(m[1] || '').toLowerCase();
      leadId = String(m[2] || '').trim();
      feedback = String(m[3] || '').trim();
      if (action === 'edit' && !feedback) action = 'edit_request';
      else if (action === 'edit' && feedback) action = 'edit_feedback';
    }
  }
}

if (allowedChatId && chatId && chatId !== allowedChatId) {
  action = '';
  leadId = '';
  feedback = '';
}

const leadActions = new Set(['approve', 'skip', 'dnc', 'edit_request', 'edit_feedback']);
const isDraftNow = action === 'draftnow';
const isLeadAction = leadActions.has(action) && !!leadId;

return [{
  json: {
    action,
    lead_id: leadId,
    feedback,
    actor,
    chat_id: chatId,
    callback_id: callbackId,
    is_draftnow: isDraftNow,
    is_lead_action: isLeadAction,
  }
}];

const stateRow = items[0]?.json || {};
const paired = items[0]?.pairedItem;
const pairedIndex = (paired && typeof paired.item === 'number') ? paired.item : 0;
const cmd = $items('Parse Ops Action', 0, 0)[pairedIndex]?.json || {};
const leadRow = $items('Lookup Lead By lead_id', 0, 0)[pairedIndex]?.json || {};

if (!cmd.is_lead_action || !cmd.lead_id) return [];

const safeText = (v, max = 300) => String(v ?? '').replace(/[\u0000-\u001F\u007F]/g, ' ').replace(/[<>]/g, '').replace(/\s+/g, ' ').trim().slice(0, max);
const leadToken = String(cmd.lead_id).replace(/[^a-zA-Z0-9_-]/g, '').slice(0, 48);
const nowIso = new Date().toISOString();

if (!leadRow.lead_id) {
  return [{ json: {
    action: cmd.action,
    lead_id: cmd.lead_id,
    callback_id: cmd.callback_id,
    should_upsert_lead: false,
    should_upsert_state: false,
    needs_approval_post: false,
    ack: `Lead ${cmd.lead_id} not found.`,
    audit_event_at: nowIso,
    audit_event_type: 'ops_not_found',
    audit_actor: cmd.actor || 'ops',
    audit_details: `Lead ${cmd.lead_id} not found`,
  } }];
}

const apiKey = String($env.OPENAI_API_KEY || '').trim();
const systemPrompt = String($env.OUTREACH_SYSTEM_PROMPT || '').trim() || 'Write concise human Telegram outreach. Do not invent facts.';
async function rewriteDraft(existingDraft, feedback) {
  if (!apiKey || apiKey.startsWith('replace-with-')) return existingDraft;
  const ctl = new AbortController();
  const t = setTimeout(() => ctl.abort(), 20000);
  try {
    const userPrompt = `Rewrite this Telegram outreach draft using the feedback. Keep under 450 chars. One question max. No hallucinations.\nDraft: ${existingDraft}\nFeedback: ${feedback}`;
    const res = await fetch('https://api.openai.com/v1/chat/completions', {
      method: 'POST',
      signal: ctl.signal,
      headers: { 'Authorization': `Bearer ${apiKey}`, 'Content-Type': 'application/json' },
      body: JSON.stringify({
        model: 'gpt-4o-mini',
        temperature: 0.5,
        messages: [
          { role: 'system', content: systemPrompt },
          { role: 'user', content: userPrompt },
        ],
      }),
    });
    if (!res.ok) throw new Error('rewrite_http');
    const data = await res.json();
    const msg = String(data?.choices?.[0]?.message?.content || '').replace(/\s+/g, ' ').trim();
    return (msg || existingDraft).slice(0, 450);
  } catch {
    return existingDraft;
  } finally {
    clearTimeout(t);
  }
}

const out = {
  lead_id: String(leadRow.lead_id || cmd.lead_id),
  name: String(leadRow.name || ''),
  telegram_username: String(leadRow.telegram_username || '').replace(/^@/, ''),
  company: String(leadRow.company || ''),
  role: String(leadRow.role || ''),
  source_url: String(leadRow.source_url || ''),
  status: String(leadRow.status || 'NEW'),
  last_contacted_at: String(leadRow.last_contacted_at || ''),
  next_followup_at: String(leadRow.next_followup_at || ''),
  followup_count: Number(leadRow.followup_count || 0),

  telegram_chat_id: String(stateRow.telegram_chat_id || ''),
  draft_message: String(stateRow.draft_message || ''),
  research_snippet: String(stateRow.research_snippet || ''),
  memory_summary: String(stateRow.memory_summary || ''),
  approval_feedback: String(stateRow.approval_feedback || ''),
  last_reply_received: String(stateRow.last_reply_received || ''),
  last_reply_at: String(stateRow.last_reply_at || ''),
  last_idempotency_key: String(stateRow.last_idempotency_key || ''),
  last_sent_type: String(stateRow.last_sent_type || ''),
  last_error: String(stateRow.last_error || ''),
  last_error_at: String(stateRow.last_error_at || ''),
  message_history: String(stateRow.message_history || ''),
  updated_at: nowIso,

  action: cmd.action,
  callback_id: cmd.callback_id,
  should_upsert_lead: true,
  should_upsert_state: true,
  needs_approval_post: false,
  ack: '',
  audit_event_at: nowIso,
  audit_event_type: `ops_${cmd.action}`,
  audit_actor: cmd.actor || 'ops',
  audit_details: '',
};

if (cmd.action === 'approve') {
  out.status = 'APPROVED';
  out.ack = `Approved ${out.lead_id}.`;
}
if (cmd.action === 'skip') {
  const next = new Date(Date.now() + 24 * 60 * 60 * 1000).toISOString();
  out.status = 'FOLLOWUP_DUE';
  out.next_followup_at = next;
  out.ack = `Skipped ${out.lead_id} for now. Revisit tomorrow.`;
}
if (cmd.action === 'dnc') {
  out.status = 'DNC';
  out.ack = `Marked ${out.lead_id} as DNC.`;
}
if (cmd.action === 'edit_request') {
  out.status = 'NEEDS_APPROVAL';
  out.ack = `Send feedback using: edit ${out.lead_id} <feedback>`;
}
if (cmd.action === 'edit_feedback') {
  const feedback = String(cmd.feedback || '').trim();
  if (!feedback) {
    out.status = 'NEEDS_APPROVAL';
    out.ack = `Feedback missing. Use: edit ${out.lead_id} <feedback>`;
  } else {
    const updatedDraft = await rewriteDraft(out.draft_message, feedback);
    out.status = 'NEEDS_APPROVAL';
    out.approval_feedback = feedback;
    out.draft_message = updatedDraft;
    out.needs_approval_post = true;
    out.ack = `Rewrote draft for ${out.lead_id}. Please approve again.`;
    out.ops_message = [
      'Approval Required (Edited)',
      `lead_id: ${safeText(out.lead_id, 120)}`,
      `name: ${safeText(out.name || 'N/A', 120)}`,
      `target: @${safeText(out.telegram_username, 120)}`,
      `feedback: ${safeText(out.approval_feedback, 280)}`,
      '',
      'Draft:',
      safeText(out.draft_message, 520),
      '',
      `Text commands: approve ${safeText(out.lead_id, 120)} | edit ${safeText(out.lead_id, 120)} <feedback> | skip ${safeText(out.lead_id, 120)} | dnc ${safeText(out.lead_id, 120)}`,
    ].join('\n');
    out.cb_approve = `approve:${leadToken}`;
    out.cb_edit = `edit:${leadToken}`;
    out.cb_skip = `skip:${leadToken}`;
    out.cb_dnc = `dnc:${leadToken}`;
  }
}

out.audit_details = out.ack;
return [{ json: out }];

const evt = $items('Telegram Events Webhook', 0, 0)[0].json || {};
const leadRows = $items('Read Leads (Inbound Match)', 0, 0).map(i => i.json || {});
const stateRows = items.map(i => i.json || {}).filter(r => String(r.lead_id || '').trim());

const senderId = String(evt.telegram_user_id || '').trim();
const text = String(evt.text || '').trim();
if (!text) return [];

const leadById = new Map(leadRows.filter(r => r.lead_id).map(r => [String(r.lead_id), r]));
const stateByLead = new Map(stateRows.map(r => [String(r.lead_id), r]));

let lead = null;
let state = null;
const evtLeadId = String(evt.lead_id || '').trim();
if (evtLeadId && leadById.has(evtLeadId)) {
  lead = leadById.get(evtLeadId);
  state = stateByLead.get(evtLeadId) || {};
} else if (senderId) {
  state = stateRows.find(r => String(r.telegram_chat_id || '').trim() === senderId) || null;
  if (state) lead = leadById.get(String(state.lead_id || '')) || null;
}

if (!lead) {
  return [{ json: { unknown_reply_alert: `Inbound reply from unknown sender ${senderId || 'unknown'}: ${text}` } }];
}

const lower = text.toLowerCase();
const isNotInterested = /(^|\b)(not interested)(\b|$)/i.test(lower);
const isStop = /(^|\b)(stop|don't message|do not message|unsubscribe|remove me)(\b|$)/i.test(lower);
const nowIso = new Date().toISOString();
const nextStatus = isStop ? 'DNC' : (isNotInterested ? 'NOT_INTERESTED' : 'REPLIED');

let summary = '';
const apiKey = String($env.OPENAI_API_KEY || '').trim();
if (!isStop && apiKey && !apiKey.startsWith('replace-with-')) {
  const ctl = new AbortController();
  const t = setTimeout(() => ctl.abort(), 20000);
  try {
    const res = await fetch('https://api.openai.com/v1/chat/completions', {
      method: 'POST',
      signal: ctl.signal,
      headers: { 'Authorization': `Bearer ${apiKey}`, 'Content-Type': 'application/json' },
      body: JSON.stringify({
        model: 'gpt-4o-mini',
        temperature: 0.3,
        messages: [
          { role: 'system', content: 'Summarize lead reply in 1-3 lines: intent, objection/need, next step.' },
          { role: 'user', content: text },
        ],
      }),
    });
    if (res.ok) {
      const data = await res.json();
      summary = String(data?.choices?.[0]?.message?.content || '').replace(/\s+/g, ' ').trim().slice(0, 350);
    }
  } catch {
  } finally {
    clearTimeout(t);
  }
}

const historyLine = `${nowIso}|INBOUND|${text}`;
return [{ json: {
  lead_id: String(lead.lead_id || ''),
  name: String(lead.name || ''),
  telegram_username: String(lead.telegram_username || '').replace(/^@/, ''),
  company: String(lead.company || ''),
  role: String(lead.role || ''),
  source_url: String(lead.source_url || ''),
  status: nextStatus,
  last_contacted_at: String(lead.last_contacted_at || ''),
  next_followup_at: '',
  followup_count: Number(lead.followup_count || 0),

  telegram_chat_id: String((state && state.telegram_chat_id) || senderId || ''),
  draft_message: String((state && state.draft_message) || ''),
  research_snippet: String((state && state.research_snippet) || ''),
  memory_summary: summary || String((state && state.memory_summary) || ''),
  approval_feedback: String((state && state.approval_feedback) || ''),
  last_reply_received: text,
  last_reply_at: nowIso,
  last_idempotency_key: String((state && state.last_idempotency_key) || ''),
  last_sent_type: String((state && state.last_sent_type) || ''),
  last_error: '',
  last_error_at: '',
  message_history: [String((state && state.message_history) || ''), historyLine].filter(Boolean).join('\n'),
  updated_at: nowIso,
  ops_reply_alert: isStop || isNotInterested
    ? `Lead ${lead.lead_id} requested stop/not interested: ${text}`
    : `New reply from lead ${lead.lead_id}: ${text}`
} }];

const leads = $items('Read Leads (Summary)', 0, 0).map(i => i.json || {});
const states = items.map(i => i.json || {});
const today = new Date().toISOString().slice(0, 10);

const sentTodayRows = leads.filter(r => String(r.last_contacted_at || '').slice(0, 10) === today);
const repliesTodayRows = states.filter(r => String(r.last_reply_at || '').slice(0, 10) === today);
const failedTodayRows = states.filter(r => String(r.last_error_at || '').slice(0, 10) === today);
const followupsToday = states.filter(r => String(r.last_sent_type || '') === 'FOLLOWUP' && sentTodayRows.some(l => String(l.lead_id || '') === String(r.lead_id || ''))).length;

const sent = sentTodayRows.length;
const replies = repliesTodayRows.length;
const rate = sent > 0 ? ((replies / sent) * 100).toFixed(1) : '0.0';
const top = repliesTodayRows.slice(0, 5).map(r => `- ${r.lead_id}: ${String(r.last_reply_received || '').slice(0, 100)}`).join('\n');

const text = [
  '*Daily Outreach Summary*',
  `Sent today: ${sent}`,
  `Replies today: ${replies} (rate ${rate}%)`,
  `Follow-ups today: ${followupsToday}`,
  `Failed today: ${failedTodayRows.length}`,
  top ? `Top replies:\n${top}` : 'Top replies: -',
].join('\n');

return [{ json: { summary_text: text } }];

const state = $getWorkflowStaticData('global');
const offset = Number(state.ops_update_offset || 0);
return [{ json: { offset } }];

const state = $getWorkflowStaticData('global');
const payload = items[0]?.json || {};
const updates = Array.isArray(payload.result) ? payload.result : [];
if (updates.length) {
  const maxId = Math.max(...updates.map(u => Number(u.update_id || 0)));
  if (Number.isFinite(maxId) && maxId > 0) state.ops_update_offset = maxId + 1;
}
return updates.map(u => ({ json: u }));
